SET NAMES utf8mb4;
START TRANSACTION;

VALUES ('BJCP_2021_CN', 'BJCP 2021 中文标准库', '2021', '中文', 'BJCP', 1, CAST('["报名必填", "支持搜索", "评审可见"]' AS JSON))
ON DUPLICATE KEY UPDATE
  name = VALUES(name),
  version = VALUES(version),
  language = VALUES(language),
  source = VALUES(source),
  status = VALUES(status),
  tags_json = VALUES(tags_json),
  update_time = NOW();

SET @bjcp_cn_library_id := (SELECT id FROM style_library WHERE code = 'BJCP_2021_CN');

DELETE FROM style_item WHERE library_id = @bjcp_cn_library_id;
DELETE FROM style_category WHERE library_id = @bjcp_cn_library_id;



COMMIT;
